type MyView struct{ ent.Schema }
func (MyView) Annotations() []schema.Annotation {
    return []schema.Annotation{
        entsql.Annotation{ViewFor: map[string]string{dialect.Postgres: "SELECT id, name FROM subjects WHERE deleted_at IS NULL"}},
    }
}
func (MyView) View() {}

